USE importease_db;

-- ====================================================================
-- TABLAS MAESTRAS
-- ====================================================================

CREATE TABLE IF NOT EXISTS fuentes_datos (
  id INT AUTO_INCREMENT PRIMARY KEY,
  codigo VARCHAR(80) NOT NULL UNIQUE,
  nombre VARCHAR(255) NOT NULL,
  url VARCHAR(500) NULL,
  descripcion TEXT NULL,
  tipo_fuente VARCHAR(80) NOT NULL,
  fecha_registro TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS arancel_secciones (
  id INT AUTO_INCREMENT PRIMARY KEY,
  numero_romano VARCHAR(10) NOT NULL UNIQUE,
  nombre TEXT NOT NULL,
  capitulo_inicio TINYINT UNSIGNED NOT NULL,
  capitulo_fin TINYINT UNSIGNED NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS arancel_hs_peru_2022 (
  id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
  codigo VARCHAR(13) NOT NULL COMMENT 'Subpartida nacional con puntos. Ej.: 0101.21.00.00',
  codigo_sin_puntos CHAR(10) NOT NULL COMMENT 'Subpartida nacional sin puntos. Ej.: 0101210000',
  descripcion TEXT NOT NULL,
  ad_valorem DECIMAL(5,2) NOT NULL DEFAULT 0.00 COMMENT 'Derecho arancelario Ad Valorem (%)',
  capitulo TINYINT UNSIGNED NULL,
  capitulo_nombre VARCHAR(255) NULL,
  partida CHAR(5) NULL,
  partida_desc TEXT NULL,
  fuente VARCHAR(255) NOT NULL DEFAULT 'Arancel de Aduanas 2022 - DS 404-2021-EF',
  pagina_pdf SMALLINT UNSIGNED NULL,
  vigente_desde DATE NOT NULL DEFAULT '2022-01-01',
  activo TINYINT(1) NOT NULL DEFAULT 1,
  created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (id),
  UNIQUE KEY uk_arancel_codigo (codigo),
  UNIQUE KEY uk_arancel_codigo_sin_puntos (codigo_sin_puntos),
  KEY idx_arancel_capitulo (capitulo),
  KEY idx_arancel_partida (partida),
  KEY idx_arancel_ad_valorem (ad_valorem),
  FULLTEXT KEY ft_arancel_descripcion (descripcion)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS usuarios (
  id INT AUTO_INCREMENT PRIMARY KEY,
  ruc VARCHAR(20) UNIQUE NOT NULL,
  razon_social VARCHAR(255) NOT NULL,
  email VARCHAR(255) UNIQUE NOT NULL,
  password_hash VARCHAR(255) NOT NULL,
  buen_contribuyente BOOLEAN DEFAULT FALSE,
  perfil VARCHAR(50) DEFAULT 'IMPORTADOR',
  fecha_registro TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  ultimo_acceso TIMESTAMP NULL DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS hs_codes (
  id INT AUTO_INCREMENT PRIMARY KEY,
  codigo VARCHAR(20) UNIQUE NOT NULL,
  descripcion_es TEXT NOT NULL,
  descripcion_en TEXT,
  capitulo INT,
  partida INT,
  subpartida INT,
  nacional INT NULL,
  ad_valorem DECIMAL(5,2) DEFAULT 0.00,
  isc DECIMAL(5,2) DEFAULT 0.00,
  igv DECIMAL(5,2) DEFAULT 18.00,
  requiere_vuce BOOLEAN DEFAULT FALSE,
  entidad_vuce VARCHAR(50),
  tlc_china BOOLEAN DEFAULT FALSE,
  fecha_actualizacion TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  FULLTEXT KEY ft_hs_descripcion (descripcion_es),
  KEY idx_hs_capitulo (capitulo),
  KEY idx_hs_partida (partida),
  KEY idx_hs_ad_valorem (ad_valorem)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS partidas_arancelarias (
  hs_code VARCHAR(20) NOT NULL,
  descripcion TEXT NOT NULL,
  ad_valorem_pct DECIMAL(5,2) DEFAULT 0.00,
  isc_pct DECIMAL(5,2) DEFAULT 0.00,
  igb_pct DECIMAL(5,2) DEFAULT 16.00,
  ipm_pct DECIMAL(5,2) DEFAULT 2.00,
  seguro_pct DECIMAL(5,2) DEFAULT 1.50,
  tendencia_actual ENUM('CRECIENTE','ESTANCADO','DECADENCIA') DEFAULT 'ESTANCADO',
  ultima_actualizacion_tendencia TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  PRIMARY KEY (hs_code),
  FULLTEXT KEY ft_partidas_descripcion (descripcion)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS vuce_restricciones (
  id INT AUTO_INCREMENT PRIMARY KEY,
  entidad VARCHAR(50) UNIQUE NOT NULL,
  tipo_control VARCHAR(255) NOT NULL,
  descripcion TEXT,
  productos_ejemplo TEXT,
  requiere_registro_sanitario BOOLEAN DEFAULT FALSE,
  tiempo_estimado_dias INT DEFAULT 15,
  enlace_tupa VARCHAR(500)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS tlc_acuerdos (
  id INT AUTO_INCREMENT PRIMARY KEY,
  pais_codigo VARCHAR(20) NOT NULL,
  pais_nombre VARCHAR(120) NOT NULL,
  acuerdo_nombre VARCHAR(255) DEFAULT NULL,
  reduccion_advalorem DECIMAL(5,2) DEFAULT NULL COMMENT 'NULL porque la preferencia depende de subpartida, cronograma y prueba de origen',
  requiere_certificado_origen BOOLEAN DEFAULT TRUE,
  fuente_codigo VARCHAR(80) DEFAULT 'ACUERDOS_COMERCIALES_PERU',
  UNIQUE KEY uk_tlc_pais_codigo (pais_codigo)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS parametros_tributarios (
  id INT AUTO_INCREMENT PRIMARY KEY,
  codigo VARCHAR(80) NOT NULL UNIQUE,
  nombre VARCHAR(255) NOT NULL,
  valor_decimal DECIMAL(12,4) NOT NULL,
  unidad VARCHAR(50) DEFAULT 'PORCENTAJE',
  descripcion TEXT NULL,
  vigente_desde DATE DEFAULT '2022-01-01',
  fuente_codigo VARCHAR(80),
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS incoterms_2020 (
  codigo VARCHAR(3) PRIMARY KEY,
  nombre VARCHAR(120) NOT NULL,
  modalidad VARCHAR(50) NOT NULL,
  descripcion_resumida TEXT,
  incluye_flete_internacional BOOLEAN DEFAULT FALSE,
  incluye_seguro_internacional BOOLEAN DEFAULT FALSE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS estados_operacion_ref (
  codigo VARCHAR(50) PRIMARY KEY,
  nombre VARCHAR(120) NOT NULL,
  descripcion TEXT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS documentos_requeridos_ref (
  id INT AUTO_INCREMENT PRIMARY KEY,
  codigo VARCHAR(80) NOT NULL UNIQUE,
  nombre VARCHAR(255) NOT NULL,
  obligatorio_base BOOLEAN DEFAULT FALSE,
  aplica_si TEXT,
  descripcion TEXT
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ====================================================================
-- TABLAS OPERATIVAS
-- ====================================================================

CREATE TABLE IF NOT EXISTS operaciones (
  id INT PRIMARY KEY AUTO_INCREMENT,
  usuario_id INT NOT NULL,
  producto_desc VARCHAR(255),
  hs_code VARCHAR(20),
  pais_origen VARCHAR(10),
  incoterm VARCHAR(10) DEFAULT 'FOB',
  fob DECIMAL(12,2),
  flete DECIMAL(12,2),
  seguro DECIMAL(12,2),
  cif DECIMAL(12,2),
  tipo_cambio DECIMAL(8,3),
  ad_valorem_aplicado DECIMAL(12,2) DEFAULT 0.00,
  isc_aplicado DECIMAL(12,2) DEFAULT 0.00,
  igv_aplicado DECIMAL(12,2) DEFAULT 0.00,
  ipm_aplicado DECIMAL(12,2) DEFAULT 0.00,
  percepcion_aplicada DECIMAL(12,2) DEFAULT 0.00,
  total_impuestos DECIMAL(12,2) DEFAULT 0.00,
  canal_asignado VARCHAR(20),
  estado VARCHAR(50) DEFAULT 'COTIZACION',
  numero_dam VARCHAR(50),
  fecha_numeracion TIMESTAMP NULL DEFAULT NULL,
  fecha_creacion TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  documento_factura BOOLEAN DEFAULT FALSE,
  documento_bl BOOLEAN DEFAULT FALSE,
  documento_certificado_origen BOOLEAN DEFAULT FALSE,
  permiso_vuce_obtenido BOOLEAN DEFAULT FALSE,
  entidad_vuce VARCHAR(50),
  FOREIGN KEY (usuario_id) REFERENCES usuarios(id) ON DELETE CASCADE,
  KEY idx_operaciones_usuario (usuario_id),
  KEY idx_operaciones_hs (hs_code),
  KEY idx_operaciones_estado (estado),
  KEY idx_operaciones_fecha (fecha_creacion)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS documentos_importacion (
  id INT AUTO_INCREMENT PRIMARY KEY,
  importacion_id INT NOT NULL,
  tipo_documento VARCHAR(80) NOT NULL,
  ruta_archivo VARCHAR(500) DEFAULT '',
  fecha_subida TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  es_obligatorio BOOLEAN DEFAULT FALSE,
  estado_validacion VARCHAR(50) DEFAULT 'PENDIENTE',
  FOREIGN KEY (importacion_id) REFERENCES operaciones(id) ON DELETE CASCADE,
  KEY idx_docs_importacion (importacion_id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS vuce_verificaciones (
  id INT AUTO_INCREMENT PRIMARY KEY,
  operacion_id INT NOT NULL,
  entidad VARCHAR(50) NOT NULL,
  requiere_permiso BOOLEAN NOT NULL,
  permiso_obtenido BOOLEAN DEFAULT FALSE,
  fecha_verificacion TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  observaciones TEXT,
  FOREIGN KEY (operacion_id) REFERENCES operaciones(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS log_busquedas (
  id INT AUTO_INCREMENT PRIMARY KEY,
  usuario_id INT DEFAULT NULL,
  termino VARCHAR(255) NOT NULL,
  resultado_hs_code VARCHAR(20),
  tipo VARCHAR(50) DEFAULT 'HS',
  fecha_busqueda TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  INDEX idx_termino (termino),
  INDEX idx_fecha (fecha_busqueda),
  INDEX idx_usuario (usuario_id),
  FOREIGN KEY (usuario_id) REFERENCES usuarios(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

CREATE TABLE IF NOT EXISTS historico_importaciones_partida (
  id INT AUTO_INCREMENT PRIMARY KEY,
  hs_code VARCHAR(20) NOT NULL,
  anio INT NOT NULL,
  volumen_importado DECIMAL(15,2) NOT NULL,
  FOREIGN KEY (hs_code) REFERENCES hs_codes(codigo) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

