-- ====================================================================

  codigo, descripcion_es, descripcion_en, capitulo, partida, subpartida, nacional,
  ad_valorem, isc, igv, requiere_vuce, entidad_vuce, tlc_china, fecha_actualizacion
)
SELECT
  codigo_sin_puntos AS codigo,
  descripcion AS descripcion_es,
  NULL AS descripcion_en,
  capitulo,
  CAST(LEFT(codigo_sin_puntos, 4) AS UNSIGNED) AS partida,
  CAST(LEFT(codigo_sin_puntos, 6) AS UNSIGNED) AS subpartida,
  NULL AS nacional,
  ad_valorem,
  0.00 AS isc,
  18.00 AS igv,
  0 AS requiere_vuce,
  NULL AS entidad_vuce,
  0 AS tlc_china,
  CURRENT_TIMESTAMP AS fecha_actualizacion
FROM arancel_hs_peru_2022
ORDER BY codigo_sin_puntos;

  hs_code, descripcion, ad_valorem_pct, isc_pct, igb_pct, ipm_pct, seguro_pct,
  tendencia_actual, ultima_actualizacion_tendencia
)
SELECT
  codigo_sin_puntos AS hs_code,
  descripcion,
  ad_valorem AS ad_valorem_pct,
  0.00 AS isc_pct,
  16.00 AS igb_pct,
  2.00 AS ipm_pct,
  1.50 AS seguro_pct,
  'ESTANCADO' AS tendencia_actual,
  CURRENT_TIMESTAMP AS ultima_actualizacion_tendencia
FROM arancel_hs_peru_2022
ORDER BY codigo_sin_puntos;

