CREATE TABLE IF NOT EXISTS reglas_restriccion (
    id INT AUTO_INCREMENT PRIMARY KEY,
    codigo_entidad VARCHAR(20) NOT NULL,
    capitulo_hs INT NULL,
    partida_hs VARCHAR(10) NULL,
    palabra_clave VARCHAR(100) NULL,
