-- ============================================================
-- 5. SOLICITUDES DE PERMISO (Expedientes creados por usuarios)
-- ============================================================
CREATE TABLE IF NOT EXISTS solicitudes_permiso (
    id INT AUTO_INCREMENT PRIMARY KEY,
    operacion_id INT NOT NULL,
    usuario_id INT NOT NULL,
    codigo_entidad VARCHAR(20) NOT NULL,
    tipo_permiso VARCHAR(255) NOT NULL,
    estado VARCHAR(50) DEFAULT 'REQUIERE_REVISION',
    numero_suce VARCHAR(100) NULL,
    numero_documento_resolutivo VARCHAR(100) NULL,
    fecha_creacion TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    fecha_envio_vuce TIMESTAMP NULL,
    fecha_aprobacion TIMESTAMP NULL,
    observaciones TEXT,
    FOREIGN KEY (operacion_id) REFERENCES operaciones(id) ON DELETE CASCADE,
    FOREIGN KEY (usuario_id) REFERENCES usuarios(id) ON DELETE CASCADE,
    FOREIGN KEY (codigo_entidad) REFERENCES entidades_control(codigo_entidad)
        ON UPDATE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ============================================================
-- 6. DATOS DE SOLICITUD (Variables autorellenadas dinÃ¡micamente)
-- ============================================================
CREATE TABLE IF NOT EXISTS solicitud_permiso_datos (
    id INT AUTO_INCREMENT PRIMARY KEY,
    solicitud_permiso_id INT NOT NULL,
    campo VARCHAR(100) NOT NULL,
    valor TEXT NOT NULL,
    origen_dato VARCHAR(100) NOT NULL,
    FOREIGN KEY (solicitud_permiso_id) REFERENCES solicitudes_permiso(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ============================================================
-- 7. DOCUMENTOS DE SOLICITUD (Checklist con estado de carga)
-- ============================================================
CREATE TABLE IF NOT EXISTS solicitud_permiso_documentos (
    id INT AUTO_INCREMENT PRIMARY KEY,
    solicitud_permiso_id INT NOT NULL,
    documento_permiso_id INT NOT NULL,
    nombre_archivo VARCHAR(255),
    ruta_archivo VARCHAR(500),
    estado VARCHAR(50) DEFAULT 'PENDIENTE',
    fecha_carga TIMESTAMP NULL,
    FOREIGN KEY (solicitud_permiso_id) REFERENCES solicitudes_permiso(id) ON DELETE CASCADE,
    FOREIGN KEY (documento_permiso_id) REFERENCES documentos_permiso(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- ============================================================
-- ÃNDICES PARA OPTIMIZACIÃ“N DE CONSULTAS
-- ============================================================
CREATE INDEX idx_reglas_capitulo ON reglas_restriccion(capitulo_hs);
CREATE INDEX idx_reglas_entidad ON reglas_restriccion(codigo_entidad);
CREATE INDEX idx_reglas_partida ON reglas_restriccion(partida_hs);
CREATE INDEX idx_solicitudes_usuario ON solicitudes_permiso(usuario_id);
CREATE INDEX idx_solicitudes_operacion ON solicitudes_permiso(operacion_id);
CREATE INDEX idx_solicitudes_estado ON solicitudes_permiso(estado);
CREATE INDEX idx_preguntas_entidad ON preguntas_permiso(codigo_entidad);
CREATE INDEX idx_documentos_entidad ON documentos_permiso(codigo_entidad);



-- ====================================================================
-- VISTAS DE CONSULTA Y VERIFICACION
-- ====================================================================
DROP VIEW IF EXISTS vw_importease_hs_real;
CREATE VIEW vw_importease_hs_real AS
SELECT
  a.codigo,
  a.codigo_sin_puntos,
  a.descripcion,
  a.ad_valorem,
  a.capitulo,
  a.capitulo_nombre,
  a.partida,
  a.partida_desc,
  a.pagina_pdf,
  h.igv,
  h.isc,
  h.requiere_vuce,
  h.entidad_vuce,
  h.tlc_china
FROM arancel_hs_peru_2022 a
LEFT JOIN hs_codes h ON h.codigo = a.codigo_sin_puntos
WHERE a.activo = 1;

DROP VIEW IF EXISTS vw_resumen_base_importease;
CREATE VIEW vw_resumen_base_importease AS
SELECT 'arancel_hs_peru_2022' AS tabla, COUNT(*) AS total_registros FROM arancel_hs_peru_2022
UNION ALL SELECT 'hs_codes', COUNT(*) FROM hs_codes
UNION ALL SELECT 'partidas_arancelarias', COUNT(*) FROM partidas_arancelarias
UNION ALL SELECT 'vuce_restricciones', COUNT(*) FROM vuce_restricciones
UNION ALL SELECT 'tlc_acuerdos', COUNT(*) FROM tlc_acuerdos
UNION ALL SELECT 'incoterms_2020', COUNT(*) FROM incoterms_2020
UNION ALL SELECT 'entidades_control', COUNT(*) FROM entidades_control
UNION ALL SELECT 'reglas_restriccion', COUNT(*) FROM reglas_restriccion
UNION ALL SELECT 'documentos_permiso', COUNT(*) FROM documentos_permiso;

-- ============================================================
-- TABLAS ADICIONALES PARA LA VERSIÃ“N 3.0 (COMPETENCIAS Y AUDITORÃA)
-- ============================================================

-- Tabla de Tipo de Cambio Diario
CREATE TABLE IF NOT EXISTS tipo_cambio_diario (
    id INT AUTO_INCREMENT PRIMARY KEY,
    fecha DATE UNIQUE NOT NULL,
    compra DECIMAL(10,4) NOT NULL,
    venta DECIMAL(10,4) NOT NULL,
    fuente VARCHAR(50) DEFAULT 'BCRP',
    fecha_consulta TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Tabla de SinÃ³nimos Arancelarios
CREATE TABLE IF NOT EXISTS hs_sinonimos (
    id INT AUTO_INCREMENT PRIMARY KEY,
    termino_usuario VARCHAR(255) NOT NULL UNIQUE,
    termino_tecnico VARCHAR(255) NOT NULL,
    codigo_hs_sugerido VARCHAR(20) NOT NULL,
    prioridad INT DEFAULT 1,
    activo BOOLEAN DEFAULT TRUE,
    fecha_creacion TIMESTAMP DEFAULT CURRENT_TIMESTAMP
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Tabla de Historial de Estados de la OperaciÃ³n
CREATE TABLE IF NOT EXISTS historial_estado_operacion (
    id INT AUTO_INCREMENT PRIMARY KEY,
    operacion_id INT NOT NULL,
    estado_anterior VARCHAR(50),
    estado_nuevo VARCHAR(50) NOT NULL,
    fecha TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    observacion TEXT,
    usuario_id INT,
    FOREIGN KEY (operacion_id) REFERENCES operaciones(id) ON DELETE CASCADE,
    FOREIGN KEY (usuario_id) REFERENCES usuarios(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Tabla de Respuestas a Cuestionarios de Permisos y Restricciones
CREATE TABLE IF NOT EXISTS respuestas_permiso_operacion (
    id INT AUTO_INCREMENT PRIMARY KEY,
    operacion_id INT NOT NULL,
    pregunta_id INT NOT NULL,
    respuesta TEXT,
    fecha_respuesta TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (operacion_id) REFERENCES operaciones(id) ON DELETE CASCADE,
    FOREIGN KEY (pregunta_id) REFERENCES preguntas_permiso(id) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Tabla de AuditorÃ­a y Trazabilidad de Eventos
CREATE TABLE IF NOT EXISTS auditoria_eventos (
    id BIGINT AUTO_INCREMENT PRIMARY KEY,
    usuario_id INT,
    accion VARCHAR(255) NOT NULL,
    modulo VARCHAR(80) NOT NULL,
    entidad_afectada VARCHAR(100),
    entidad_id INT,
    detalle TEXT,
    ip_origen VARCHAR(80),
    user_agent VARCHAR(255),
    fecha_evento TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
    FOREIGN KEY (usuario_id) REFERENCES usuarios(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

-- Tabla de Trazabilidad y Fuentes de Reglas Aduaneras
CREATE TABLE IF NOT EXISTS fuentes_revision_reglas (
    id INT AUTO_INCREMENT PRIMARY KEY,
    regla_id INT NOT NULL,
    fuente_legal VARCHAR(255) NOT NULL,
    fecha_revision DATE NOT NULL,
    vigente BOOLEAN DEFAULT TRUE,
    observacion TEXT,
    usuario_modifico_id INT,
    FOREIGN KEY (regla_id) REFERENCES reglas_restriccion(id) ON DELETE CASCADE,
    FOREIGN KEY (usuario_modifico_id) REFERENCES usuarios(id) ON DELETE SET NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

