-- ============================================================
-- 4. DOCUMENTOS DE PERMISO (Checklist documental TUPA por entidad)
-- ============================================================
CREATE TABLE IF NOT EXISTS documentos_permiso (
    id INT AUTO_INCREMENT PRIMARY KEY,
