INSERT INTO incoterms_2020 (codigo, nombre, modalidad, descripcion_resumida, incluye_flete_internacional, incluye_seguro_internacional) VALUES
('EXW', 'Ex Works', 'MULTIMODAL', 'Entrega en establecimiento del vendedor; el comprador asume casi todos los costos y riesgos.', 0, 0),
('FCA', 'Free Carrier', 'MULTIMODAL', 'Entrega al transportista designado por el comprador en el lugar acordado.', 0, 0),
('CPT', 'Carriage Paid To', 'MULTIMODAL', 'Vendedor paga transporte hasta destino convenido; riesgo se transmite al entregar al transportista.', 1, 0),
('CIP', 'Carriage and Insurance Paid To', 'MULTIMODAL', 'Vendedor paga transporte y seguro hasta destino convenido.', 1, 1),
('DAP', 'Delivered At Place', 'MULTIMODAL', 'Entrega en lugar de destino convenido, sin descargar y sin despacho de importacion.', 1, 0),
('DPU', 'Delivered at Place Unloaded', 'MULTIMODAL', 'Entrega descargada en lugar de destino convenido, sin despacho de importacion.', 1, 0),
('DDP', 'Delivered Duty Paid', 'MULTIMODAL', 'Vendedor entrega con despacho de importacion y tributos pagados, si se pacto asi.', 1, 0),
('FAS', 'Free Alongside Ship', 'MARITIMO', 'Entrega al costado del buque en puerto de embarque.', 0, 0),
('FOB', 'Free On Board', 'MARITIMO', 'Entrega a bordo del buque en puerto de embarque.', 0, 0),
('CFR', 'Cost and Freight', 'MARITIMO', 'Vendedor paga costo y flete hasta puerto de destino; seguro no incluido.', 1, 0),
('CIF', 'Cost, Insurance and Freight', 'MARITIMO', 'Vendedor paga costo, seguro y flete hasta puerto de destino.', 1, 1);
INSERT INTO vuce_restricciones (entidad, tipo_control, descripcion, productos_ejemplo, requiere_registro_sanitario, tiempo_estimado_dias, enlace_tupa) VALUES
('MTC', 'Homologacion de equipos de telecomunicaciones', 'Control aplicable, segun corresponda, a equipos que usan radiofrecuencia, telefonia movil, WiFi, Bluetooth u otros sistemas de telecomunicaciones.', 'Celulares, routers, transmisores, radios, smartwatches, equipos con WiFi o Bluetooth.', 0, 20, 'https://www.vuce.gob.pe/'),
('DIGESA', 'Control sanitario de alimentos y productos de consumo humano', 'Control sanitario referencial para alimentos industrializados, bebidas, envases en contacto con alimentos y productos vinculados al consumo humano, segun el procedimiento aplicable.', 'Alimentos procesados, bebidas, suplementos alimenticios, envases para alimentos.', 1, 15, 'https://www.vuce.gob.pe/'),
('DIGEMID', 'Control sanitario de productos farmaceuticos, dispositivos medicos y productos sanitarios', 'Control aplicable, segun corresponda, a medicamentos, dispositivos medicos, productos sanitarios y otros bienes bajo competencia sanitaria.', 'Medicamentos, vitaminas terapeuticas, jeringas, equipos medicos, cosmeticos regulados.', 1, 30, 'https://www.vuce.gob.pe/'),
('SENASA', 'Control fitosanitario y zoosanitario', 'Control aplicable a plantas, animales, productos vegetales, productos pecuarios y otros bienes sujetos a sanidad agraria.', 'Semillas, plantas, frutas frescas, animales vivos, carnes y productos agropecuarios.', 0, 10, 'https://www.vuce.gob.pe/'),
('SANIPES', 'Control sanitario pesquero y acuicola', 'Control aplicable a recursos hidrobiologicos, productos pesqueros y acuicolas, segun procedimiento vigente.', 'Pescados, mariscos, conservas pesqueras, productos acuicolas.', 0, 10, 'https://www.vuce.gob.pe/'),
('PRODUCE', 'Control sectorial de produccion', 'Control sectorial aplicable a determinados bienes industriales, pesqueros o manufactureros, segun normativa vigente.', 'Productos industriales o pesqueros sujetos a autorizacion sectorial.', 0, 15, 'https://www.vuce.gob.pe/'),
('SERFOR', 'Control de flora y fauna silvestre', 'Control aplicable a especies de flora y fauna silvestre, maderas, productos forestales y bienes sujetos a normativa CITES o forestal.', 'Maderas, pieles, fauna silvestre, productos forestales.', 0, 20, 'https://www.vuce.gob.pe/'),
('SUCAMEC', 'Control de armas, municiones, explosivos y productos relacionados', 'Control aplicable a armas, municiones, explosivos, pirotecnia y materiales relacionados, segun normativa vigente.', 'Municiones, explosivos, pirotecnicos, accesorios controlados.', 0, 30, 'https://www.vuce.gob.pe/');
